import React from "react";

const TestimonialCard = ({ testimonial }) => {
  const { name = "User", text = "Sin mensaje.", img = "", rating = 5 } = testimonial || {};

  return (
    <div
      style={{
        width: "400px",
        minHeight: "300px",
        backgroundColor: "#f5f5f5",
        borderRadius: "15px",
        boxShadow: "0 4px 15px rgba(0,0,0,0.1)",
        padding: "2rem",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        textAlign: "center",
      }}
    >
      <div style={{ marginBottom: "1rem", fontWeight: "bold" }}>Foto de {name}</div>
      <div style={{ marginBottom: "0.5rem", color: "#FFD700" }}>
        {"★".repeat(rating)}{"☆".repeat(5 - rating)}
      </div>
      <p style={{ marginBottom: "1rem" }}>"{text}"</p>
      <strong style={{ color: "#003E73" }}>{name}</strong>
    </div>
  );
};

export default TestimonialCard;
